function toTraditionalChinese(input) {
  let output = input;

  traditionalPhraseMap.forEach((traditional, simplified) => {
    output = output.replaceAll(simplified, traditional);
  });

  return Array.from(output, (character) => traditionalCharMap[character] || character).join("");
}

const languageNames = {
  en: "English",
  zhHans: "Simplified Chinese",
  zhHant: "Traditional Chinese",
};

const buttons = document.querySelectorAll("[data-language]");
const translatedElements = document.querySelectorAll("[data-i18n]");
const mayArticle = document.querySelector("[data-may-article]");
const defaultMayArticleHtml = mayArticle?.innerHTML;
const subscribeForm = document.querySelector(".subscribe-form");

function renderMayArticle(language) {
  if (!mayArticle || !defaultMayArticleHtml) {
    return;
  }

  if (language === "zhHans") {
    mayArticle.innerHTML = mayZhHansArticleHtml;
    return;
  }

  if (language === "zhHant") {
    mayArticle.innerHTML = toTraditionalChinese(mayZhHansArticleHtml);
    return;
  }

  mayArticle.innerHTML = defaultMayArticleHtml;
}

function setLanguage(language) {
  const dictionary = translations[language] || translations.en;

  translatedElements.forEach((element) => {
    const key = element.dataset.i18n;

    if (dictionary[key]) {
      element.textContent = dictionary[key];
    }
  });

  buttons.forEach((button) => {
    const isActive = button.dataset.language === language;
    button.classList.toggle("active", isActive);
    button.setAttribute("aria-pressed", String(isActive));
    button.setAttribute("aria-label", `Translate to ${languageNames[button.dataset.language]}`);
  });

  document.documentElement.lang = language === "en" ? "en" : language === "zhHans" ? "zh-Hans" : "zh-Hant";
  renderMayArticle(language);
  localStorage.setItem("newsletter-language", language);
}

buttons.forEach((button) => {
  button.addEventListener("click", () => {
    setLanguage(button.dataset.language);
  });
});

subscribeForm?.addEventListener("submit", (event) => {
  event.preventDefault();
});

setLanguage(localStorage.getItem("newsletter-language") || "en");
